import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is probability?", a: "Probability measures how likely an event is to happen. It ranges from 0 to 1, or 0% to 100%. A probability of 0 means impossible, while 1 means certain." },
  { q: "How do you calculate the probability of two events?", a: "For independent events, P(A and B) = P(A) x P(B). For either event happening, P(A or B) = P(A) + P(B) - P(A and B)." },
  { q: "What is conditional probability?", a: "Conditional probability is the chance of one event happening given that another event has already happened. It is written P(A|B) and calculated as P(A and B) / P(B)." },
  { q: "What is the complement of an event?", a: "The complement is the chance that an event does not happen. If P(A) is the probability of event A, then the complement is 1 - P(A)." },
  { q: "What is the difference between theoretical and experimental probability?", a: "Theoretical probability comes from expected outcomes, such as 1 out of 6 for rolling a die. Experimental probability comes from actual observed results after trials." },
];

type Mode = "single" | "multiple" | "conditional" | "complement";
const pct = (value: number) => `${(value * 100).toFixed(2)}%`;

export default function ProbabilityCalculator() {
  const [mode, setMode] = useState<Mode>("single");
  const [fav, setFav] = useState(2);
  const [total, setTotal] = useState(10);
  const [probA, setProbA] = useState(0.4);
  const [probB, setProbB] = useState(0.5);
  const [operator, setOperator] = useState<"and" | "or">("and");
  const [joint, setJoint] = useState(0.2);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (mode === "single") {
      if (total <= 0 || fav < 0 || fav > total) return { label: "Invalid input", value: "Check outcomes", step: "Favorable outcomes must be between 0 and total outcomes." };
      const p = fav / total;
      return { label: "Single Event Probability", value: pct(p), step: `P(A) = favorable / total = ${fav} / ${total} = ${p.toFixed(4)} = ${pct(p)}.` };
    }
    if (mode === "multiple") {
      const value = operator === "and" ? probA * probB : probA + probB - probA * probB;
      return { label: `P(A ${operator.toUpperCase()} B)`, value: pct(value), step: operator === "and" ? `For independent events, P(A and B) = ${probA} x ${probB} = ${value.toFixed(4)}.` : `For independent events, P(A or B) = ${probA} + ${probB} - (${probA} x ${probB}) = ${value.toFixed(4)}.` };
    }
    if (mode === "conditional") {
      if (probB <= 0) return { label: "Invalid input", value: "P(B) must be greater than 0", step: "Conditional probability divides by P(B), so P(B) cannot be zero." };
      const value = joint / probB;
      return { label: "Conditional Probability", value: pct(value), step: `P(A|B) = P(A and B) / P(B) = ${joint} / ${probB} = ${value.toFixed(4)}.` };
    }
    const value = 1 - probA;
    return { label: "Complement Probability", value: pct(value), step: `P(not A) = 1 - P(A) = 1 - ${probA} = ${value.toFixed(4)}.` };
  }, [mode, fav, total, probA, probB, operator, joint]);

  return (
    <>
      <SEOHead title="Free Probability Calculator Online - Calculate Any Probability Instantly | CalcHive" description="Free online probability calculator. Calculate single event, multiple event, conditional and complement probability instantly with step by step solution. 100% free for students, no signup required." canonical="/probability-calculator" keywords="free probability calculator, probability calculator online free, calculate probability free, conditional probability calculator free, multiple event probability calculator free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Probability Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this probability calculator online free to calculate probability free for single events, multiple events, conditional probability, and complements.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6"><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="single">Single event probability</option><option value="multiple">Multiple event probability</option><option value="conditional">Conditional probability</option><option value="complement">Complement probability</option></select></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {mode === "single" && <><div><label htmlFor="fav" className="text-sm font-semibold text-foreground block mb-2">Favorable outcomes</label><input id="fav" type="number" inputMode="decimal" value={fav} onChange={(event) => setFav(Number(event.target.value))} className={inputClass} /></div><div><label htmlFor="total" className="text-sm font-semibold text-foreground block mb-2">Total outcomes</label><input id="total" type="number" inputMode="decimal" value={total} onChange={(event) => setTotal(Number(event.target.value))} className={inputClass} /></div></>}
            {mode === "multiple" && <><div><label htmlFor="prob-a" className="text-sm font-semibold text-foreground block mb-2">P(A) as decimal</label><input id="prob-a" type="number" step="0.01" inputMode="decimal" value={probA} onChange={(event) => setProbA(Number(event.target.value))} className={inputClass} /></div><div><label htmlFor="prob-b" className="text-sm font-semibold text-foreground block mb-2">P(B) as decimal</label><input id="prob-b" type="number" step="0.01" inputMode="decimal" value={probB} onChange={(event) => setProbB(Number(event.target.value))} className={inputClass} /></div><div><label htmlFor="operator" className="text-sm font-semibold text-foreground block mb-2">Relationship</label><select id="operator" value={operator} onChange={(event) => setOperator(event.target.value as "and" | "or")} className={inputClass}><option value="and">A and B</option><option value="or">A or B</option></select></div></>}
            {mode === "conditional" && <><div><label htmlFor="joint" className="text-sm font-semibold text-foreground block mb-2">P(A and B)</label><input id="joint" type="number" step="0.01" inputMode="decimal" value={joint} onChange={(event) => setJoint(Number(event.target.value))} className={inputClass} /></div><div><label htmlFor="prob-b-cond" className="text-sm font-semibold text-foreground block mb-2">P(B)</label><input id="prob-b-cond" type="number" step="0.01" inputMode="decimal" value={probB} onChange={(event) => setProbB(Number(event.target.value))} className={inputClass} /></div></>}
            {mode === "complement" && <div><label htmlFor="prob-a-comp" className="text-sm font-semibold text-foreground block mb-2">P(A) as decimal</label><input id="prob-a-comp" type="number" step="0.01" inputMode="decimal" value={probA} onChange={(event) => setProbA(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${result.value}-${result.step}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight" data-testid="result-probability">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Probability for Any Event for Free</h2><p className="text-muted-foreground leading-relaxed">For a single event, divide favorable outcomes by total outcomes. For advanced modes, enter probabilities as decimals between 0 and 1.</p>
          <h2 className="text-2xl font-bold text-foreground">Single vs Multiple Event Probability Explained</h2><p className="text-muted-foreground leading-relaxed">Single event probability looks at one outcome. Multiple event probability combines two probabilities using and/or rules for independent events.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Statistics Probability Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this conditional probability calculator free and multiple event probability calculator free for homework, practice, and quick checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/probability-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


